// Solution
function findDuplicates(arr) {
  let unique = new Set();
  let result = [];
  for (let num of arr) {
    if (unique.has(num)) {
      result.push(num);
    }
    unique.add(num);
  }
  return result;
}

solutions.python:
class Solution:
  def findDuplicates(self, s: list[int]) -> list[int]:
    unique = set()
    result = []
    for num in s:
      if num in unique:
        result.append(num)
      unique.add(num)
    return result
